import 'package:cloud_firestore/cloud_firestore.dart';
import '../../../../core/constants/firestore_collections.dart';
import '../../../../core/services/firebase/firestore_service.dart';
import '../../domain/entities/favorite.dart';
import '../../domain/repositories/favorite_repository.dart';
class FavoriteRepositoryImpl implements FavoriteRepository { final FirestoreService fs; const FavoriteRepositoryImpl(this.fs); CollectionReference<Map<String,dynamic>> get favorites=>fs.collection(FirestoreCollections.favorites); String id(String u,String p)=>'${u}_$p'; @override Stream<List<Favorite>> watchMyFavorites(String userId)=>favorites.where('userId',isEqualTo:userId).orderBy('createdAt',descending:true).snapshots().map((s)=>s.docs.map((d)=>Favorite.fromMap(d.id,d.data())).toList()); @override Future<bool> isFavorite({required String userId,required String productId}) async => (await favorites.doc(id(userId,productId)).get()).exists; @override Future<void> addFavorite({required String userId,required String productId})=>favorites.doc(id(userId,productId)).set({'userId':userId,'productId':productId,'createdAt':FieldValue.serverTimestamp()},SetOptions(merge:true)); @override Future<void> removeFavorite({required String userId,required String productId})=>favorites.doc(id(userId,productId)).delete(); @override Future<void> toggleFavorite({required String userId,required String productId}) async { if(await isFavorite(userId:userId,productId:productId)){await removeFavorite(userId:userId,productId:productId);}else{await addFavorite(userId:userId,productId:productId);} } }
